export const ImpactType = {
  PROBLEM: 'PROBLEM',
  INITIATIVE: 'INITIATIVE'
} as const;

export type ImpactType = typeof ImpactType[keyof typeof ImpactType];

export interface Milestone {
  id: string;
  title: string;
  description: string;
  isCompleted: boolean;
  dueDate?: string;
  updatedAt?: string;
}

export interface Comment {
  id: string;
  author: string;
  text: string;
  timestamp: string;
  votes: number;
  isSolutionProposal?: boolean;
}

export interface ImpactEntry {
  id: string;
  type: ImpactType;
  title: string;
  description: string;
  author: string;
  location: string;
  region: string;
  timestamp: string;
  votes: number;
  tags: string[];
  comments: Comment[];
  milestones?: Milestone[];
  participantsCount?: number;
  participantsList?: string[];
  status?: 'active' | 'completed' | 'on-hold' | 'needs-solution';
  linkedProblemId?: string;
  linkedInitiativeIds?: string[];
  followersCount: number;
}

export interface UserStats {
  problemsReported: number;
  initiativesJoined: number;
  milestonesReached: number;
  totalKarma: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Milestone } from "../types.ts";

const getAI = () => {
  const apiKey = typeof process !== 'undefined' ? process.env.API_KEY : undefined;
  return new GoogleGenAI({ apiKey: apiKey || '' });
};

export const analyzeProblem = async (problemDescription: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze the following local community problem. Provide tags, a severity score (1-10), and 3 distinct initiative approaches that could solve it: "${problemDescription}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tags: { type: Type.ARRAY, items: { type: Type.STRING } },
            severity: { type: Type.NUMBER },
            summary: { type: Type.STRING },
            suggestedInitiatives: { 
              type: Type.ARRAY, 
              items: { 
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  impactLevel: { type: Type.STRING }
                },
                required: ["title", "description", "impactLevel"]
              } 
            }
          },
          required: ["tags", "severity", "summary", "suggestedInitiatives"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini analyzeProblem error:", error);
    return { 
      tags: ['community'], 
      severity: 5, 
      summary: "We're analyzing the impact of this report.",
      suggestedInitiatives: [] 
    };
  }
};

export const generateMilestones = async (initiativeTitle: string, description: string): Promise<Milestone[]> => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a realistic 5-step milestone roadmap for a local initiative called "${initiativeTitle}". The initiative is described as: ${description}. Ensure steps are actionable for a community group.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["title", "description"]
          }
        }
      }
    });

    const raw = JSON.parse(response.text || '[]');
    return raw.map((m: any, idx: number) => ({
      id: `m-${idx}-${Date.now()}`,
      title: m.title,
      description: m.description,
      isCompleted: false,
      updatedAt: new Date().toISOString()
    }));
  } catch (error) {
    console.error("Gemini generateMilestones error:", error);
    return [
      { id: 'm1', title: 'Community Kickoff', description: 'Host a meeting to align on goals.', isCompleted: false },
      { id: 'm2', title: 'Resource Audit', description: 'List the tools and skills available.', isCompleted: false },
      { id: 'm3', title: 'Action Phase', description: 'Execute the primary tasks.', isCompleted: false }
    ];
  }
};

