const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: any) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (initialType) setType(initialType);
      if (prefilledTitle) setTitle(prefilledTitle);
    }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try {
        const result = await analyzeProblem(description);
        setAiAnalysis(result);
        setStep(2);
      } catch (e) {
        console.error(e);
        setStep(2);
      } finally {
        setLoading(false);
      }
    } else {
      onSubmit({ title, description, type, tags: aiAnalysis?.tags || ['general'] });
      reset();
    }
  };

  const reset = () => { setStep(1); setTitle(''); setDescription(''); setAiAnalysis(null); onClose(); };
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-950/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl overflow-hidden flex flex-col max-h-[90vh] border border-gray-100 border-t-8 border-t-gray-900">
