        <div className="p-8 overflow-y-auto space-y-8">
          {step === 1 ? (
            <>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">Category of action</label>
                <div className="grid grid-cols-2 gap-4">
                  {[
                    { id: ImpactType.PROBLEM, label: 'Report Issue', color: 'text-amber-600', active: 'bg-amber-50 border-amber-200' },
                    { id: ImpactType.INITIATIVE, label: 'Start Project', color: 'text-emerald-600', active: 'bg-emerald-50 border-emerald-200' },
