                    >
                      {btn.label}
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">What is the focus?</label>
                <input 
                  value={title}
                  onChange={e => setTitle(e.target.value)}
