const Feed = ({ entries, joinedIds, onVote, onViewDetail, onJoin, userRegion }: any) => {
  const [filter, setFilter] = useState<'all' | 'problems' | 'initiatives'>('all');
  const [scope, setScope] = useState<'local' | 'global'>('local');

  const filteredEntries = useMemo(() => {
    let result = entries;
    if (scope === 'local') result = result.filter((e: ImpactEntry) => e.region === userRegion);
    if (filter === 'problems') result = result.filter((e: ImpactEntry) => e.type === ImpactType.PROBLEM);
    if (filter === 'initiatives') result = result.filter((e: ImpactEntry) => e.type === ImpactType.INITIATIVE);
    return result;
  }, [entries, filter, scope, userRegion]);

  return (
    <div className="space-y-6 max-w-2xl mx-auto py-6 px-4">
      <div className="bg-gray-900 rounded-[2rem] p-8 text-white relative overflow-hidden mb-12 shadow-2xl">
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-4">
            <span className="bg-emerald-500 h-2 w-2 rounded-full animate-pulse"></span>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-400">Live in {userRegion}</span>
          </div>
          <h2 className="text-3xl font-black tracking-tighter mb-2 leading-none">Your Local Node</h2>
          <p className="text-gray-400 font-medium text-sm leading-relaxed max-w-sm">
            {filteredEntries.length} active initiatives and problems identified in your immediate area.
          </p>
        </div>
        <div className="absolute -right-8 -bottom-8 opacity-10">
           <Globe size={240} strokeWidth={1} />
        </div>
      </div>

      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mb-4">
        <div className="flex items-center bg-gray-100 p-1 rounded-2xl border border-gray-200">
          <button onClick={() => setScope('local')} className={`px-4 py-2 text-xs font-black rounded-xl transition-all uppercase tracking-widest ${scope === 'local' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500'}`}>My Area</button>
          <button onClick={() => setScope('global')} className={`px-4 py-2 text-xs font-black rounded-xl transition-all uppercase tracking-widest ${scope === 'global' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500'}`}>Global</button>
        </div>

        <div className="flex items-center gap-2">
          {['all', 'problems', 'initiatives'].map((f: any) => (
            <button key={f} onClick={() => setFilter(f)} className={`px-3 py-1.5 text-[9px] font-black uppercase tracking-widest rounded-xl border transition-all ${filter === f ? 'bg-gray-900 border-gray-900 text-white' : 'bg-white border-gray-200 text-gray-400 hover:border-gray-900'}`}>{f}</button>
          ))}
        </div>
      </div>

      <div className="space-y-4">
        {filteredEntries.map((entry: ImpactEntry) => (
          <ImpactCard key={entry.id} entry={entry} onVote={onVote} onClick={onViewDetail} onJoin={onJoin} isJoined={joinedIds.has(entry.id)} />
        ))}
      </div>
    </div>
  );
};

const AppContent = () => {
  const [entries, setEntries] = useState<ImpactEntry[]>(INITIAL_ENTRIES);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [joinedIds, setJoinedIds] = useState<Set<string>>(new Set());
  const [view, setView] = useState<'feed' | 'dashboard' | 'map'>('feed');
  const [createConfig, setCreateConfig] = useState<{type?: ImpactType, title?: string, problemId?: string}>({});
  const [userRegion, setUserRegion] = useState<string>('Central');
  const [userStats, setUserStats] = useState<UserStats>({
    problemsReported: 0, initiativesJoined: 0, milestonesReached: 1, totalKarma: 420
  });

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(() => setUserRegion('Central'));
    }
  }, []);

  const handleVote = (id: string, delta: number) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, votes: e.votes + delta } : e));
  };

  const handleJoin = (id: string) => {
    setJoinedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
        setUserStats(s => ({ ...s, initiativesJoined: Math.max(0, s.initiativesJoined - 1) }));
      } else {
        next.add(id);
        setUserStats(s => ({ ...s, initiativesJoined: s.initiativesJoined + 1, totalKarma: s.totalKarma + 50 }));
      }
      return next;
    });
  };

  const handleToggleMilestone = (milestoneId: string) => {
    if (!selectedId) return;
    setEntries(prev => prev.map(entry => {
      if (entry.id !== selectedId || !entry.milestones) return entry;
      const mIdx = entry.milestones.findIndex(m => m.id === milestoneId);
      const wasCompleted = entry.milestones[mIdx].isCompleted;
      if (!wasCompleted) setUserStats(s => ({ ...s, milestonesReached: s.milestonesReached + 1, totalKarma: s.totalKarma + 25 }));
      return {
        ...entry,
        milestones: entry.milestones.map(m => m.id === milestoneId ? { ...m, isCompleted: !m.isCompleted } : m)
      };
    }));
  };

  const handlePost = async (partial: Partial<ImpactEntry>) => {
    let milestones: Milestone[] = [];
    if (partial.type === ImpactType.INITIATIVE) {
      milestones = await generateMilestones(partial.title!, partial.description!);
    }
    const newId = Date.now().toString();
    const newEntry: ImpactEntry = {
      id: newId, type: partial.type!, title: partial.title!, description: partial.description!,
      author: 'you', location: `Near ${userRegion}`, region: userRegion, timestamp: 'Just now',
      votes: 1, followersCount: 1, tags: partial.tags || [], comments: [],
      participantsCount: partial.type === ImpactType.INITIATIVE ? 1 : 0,
      milestones: partial.type === ImpactType.INITIATIVE ? milestones : undefined,
      status: 'active', linkedProblemId: createConfig.problemId
    };
    setEntries(prev => {
      let updated = [newEntry, ...prev];
      if (createConfig.problemId) {
        updated = updated.map(e => (e.id === createConfig.problemId) ? { ...e, linkedInitiativeIds: [...(e.linkedInitiativeIds || []), newId] } : e);
      }
      return updated;
    });
    if (partial.type === ImpactType.PROBLEM) setUserStats(s => ({ ...s, problemsReported: s.problemsReported + 1, totalKarma: s.totalKarma + 100 }));
    setIsModalOpen(false); setCreateConfig({}); setSelectedId(newId);
    if (partial.type === ImpactType.INITIATIVE) handleJoin(newId);
  };

  const selectedEntry = entries.find(e => e.id === selectedId);
  const linkedEntries = selectedEntry?.linkedInitiativeIds ? entries.filter(e => selectedEntry.linkedInitiativeIds?.includes(e.id)) : undefined;

  return (
    <div className="min-h-screen flex flex-col bg-white font-inter">
      <nav className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-gray-100 h-20 flex items-center px-6 sm:px-12">
        <div className="max-w-7xl mx-auto w-full flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => { setSelectedId(null); setView('feed'); }}>
            <div className="w-11 h-11 bg-gray-900 rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-105 transition-all">
              <Zap className="text-emerald-400" size={24} strokeWidth={3} />
            </div>
            <div className="hidden sm:block">
              <span className="text-2xl font-black text-gray-900 tracking-tighter block leading-none">ImpactHack</span>
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-0.5 block">Community Action</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button onClick={() => { setCreateConfig({}); setIsModalOpen(true); }} className="bg-gray-900 text-white px-6 py-3 rounded-2xl font-black text-sm hover:bg-black transition-all shadow-xl active:scale-95 flex items-center gap-2">
               <PlusCircle size={20} /> <span className="hidden md:inline">Report Impact</span>
             </button>
             <div className="w-12 h-12 rounded-2xl bg-gray-100 border border-gray-200 cursor-pointer overflow-hidden hover:border-gray-900 transition-all shadow-sm" onClick={() => setView('dashboard')}>
                <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Felix" alt="User" className="w-full h-full object-cover" />
             </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl mx-auto w-full flex flex-col md:flex-row gap-12 p-6 lg:p-12">
        <aside className="hidden md:flex flex-col w-64 shrink-0 gap-2 sticky top-32 h-fit">
          <nav className="space-y-1">
            {[
              { id: 'feed', icon: <Home size={20} />, label: 'Action Feed' },
              { id: 'dashboard', icon: <Layout size={20} />, label: 'Impact Dashboard' },
              { id: 'map', icon: <MapIcon size={20} />, label: 'Community Map' },
            ].map(item => (
              <button key={item.id} onClick={() => { setView(item.id as any); setSelectedId(null); }} className={`w-full flex items-center gap-4 px-4 py-3 font-black text-sm rounded-2xl transition-all ${view === item.id && !selectedId ? 'bg-gray-900 text-white shadow-xl' : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900'}`}>
                {item.icon} {item.label}
              </button>
            ))}
          </nav>
        </aside>

        <div className="flex-1 min-w-0">
          {selectedId && selectedEntry ? (
            <DetailView 
              entry={selectedEntry} 
              isJoined={joinedIds.has(selectedEntry.id)} 
              onVote={handleVote} 
              onToggleMilestone={handleToggleMilestone}
              onBack={() => setSelectedId(null)}
              onJoin={handleJoin}
              onAddComment={(id: string, text: string) => {
                const comment = { id: Date.now().toString(), author: 'you', text, timestamp: 'Just now', votes: 0 };
                setEntries(prev => prev.map(e => e.id === id ? { ...e, comments: [comment, ...e.comments] } : e));
              }}
              onProposeInitiative={(problem: ImpactEntry) => { setCreateConfig({ type: ImpactType.INITIATIVE, title: `Solution: ${problem.title}`, problemId: problem.id }); setIsModalOpen(true); }}
              linkedEntries={linkedEntries} 
            />
          ) : view === 'dashboard' ? (
            <DashboardView stats={userStats} entries={entries} joinedIds={joinedIds} />
          ) : (
            <Feed entries={entries} joinedIds={joinedIds} onVote={handleVote} onViewDetail={setSelectedId} onJoin={handleJoin} userRegion={userRegion} />
          )}
        </div>
      </main>

      <CreateModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSubmit={handlePost} initialType={createConfig.type} prefilledTitle={createConfig.title} />
    </div>
  );
};

