const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: any) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (isOpen) { setType(initialType || ImpactType.PROBLEM); setTitle(prefilledTitle || ''); }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try { const result = await analyzeProblem(description); setAiAnalysis(result); setStep(2); } catch (e) { setStep(2); } finally { setLoading(false); }
    } else {
      onSubmit({ title, description, type, tags: aiAnalysis?.tags || ['general'] });
      setStep(1); setTitle(''); setDescription(''); setAiAnalysis(null); onClose();
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-950/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl overflow-hidden flex flex-col max-h-[90vh] border border-gray-100 border-t-8 border-t-gray-900">
        <div className="p-8 border-b border-gray-50 flex justify-between items-center"><h3 className="text-2xl font-black text-gray-900 tracking-tighter flex items-center gap-3">{step === 1 ? <Zap size={24} className="text-emerald-500" /> : <Sparkles size={24} className="text-indigo-500" />}{step === 1 ? 'New Impact Action' : 'Refinement'}</h3><button onClick={onClose} className="text-gray-300 hover:text-gray-900 transition-colors"><X size={28} /></button></div>
        <div className="p-8 overflow-y-auto space-y-8">
          {step === 1 ? (
            <>
              <div><label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">Category</label><div className="grid grid-cols-2 gap-4">{[ { id: ImpactType.PROBLEM, label: 'Report Issue', color: 'text-amber-600', active: 'bg-amber-50 border-amber-200' }, { id: ImpactType.INITIATIVE, label: 'Start Project', color: 'text-emerald-600', active: 'bg-emerald-50 border-emerald-200' } ].map(btn => ( <button key={btn.id} onClick={() => setType(btn.id as any)} className={`py-4 rounded-2xl text-sm font-black border-2 ${type === btn.id ? btn.active + ' ' + btn.color : 'bg-gray-50 border-gray-50 text-gray-400 hover:border-gray-200'}`}>{btn.label}</button> ))}</div></div>
              <div><label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Focus</label><input value={title} onChange={e => setTitle(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-2 border-gray-50 focus:bg-white focus:border-gray-900 outline-none font-black text-lg" placeholder="e.g. Park Restoration" /></div>
              <div><label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Context</label><textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-2 border-gray-50 focus:bg-white focus:border-gray-900 outline-none h-40 resize-none font-medium" placeholder="Tell the community what's happening..." /></div>
            </>
          ) : (
            <div className="space-y-8">
              <div className="bg-gray-900 rounded-[2rem] p-8 text-white shadow-2xl relative overflow-hidden"><div className="relative z-10"><div className="flex items-center gap-3 mb-4"><Shield className="text-emerald-400" size={24} /><span className="font-black text-sm uppercase tracking-widest">Impact Analysis</span></div><p className="text-gray-300 font-medium mb-6 text-lg leading-snug">{aiAnalysis?.summary || "Analyzing community readiness..."}</p><div className="flex gap-2 flex-wrap">{aiAnalysis?.tags?.map((tag: string) => ( <span key={tag} className="text-[10px] font-black px-3 py-1 bg-white/10 rounded-full uppercase tracking-widest border border-white/5">#{tag}</span> ))}</div></div><Sparkles className="absolute -right-8 -bottom-8 opacity-10" size={160} /></div>
              {aiAnalysis?.suggestedInitiatives && aiAnalysis.suggestedInitiatives.length > 0 && ( <div><h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">Proposals:</h4><div className="space-y-4">{aiAnalysis.suggestedInitiatives.map((si: any, i: number) => ( <div key={i} className="p-6 border-2 border-gray-50 rounded-[1.5rem] hover:border-gray-900 transition-all cursor-pointer group"><div className="flex justify-between items-start mb-2"><div className="font-black text-gray-900 tracking-tight">{si.title}</div><span className="text-[10px] font-black uppercase text-emerald-500">{si.impactLevel}</span></div><div className="text-gray-500 text-sm font-medium leading-relaxed">{si.description}</div></div> ))}</div></div> )}
            </div>
          )}
        </div>
        <div className="p-8 border-t border-gray-50 bg-gray-50/50 flex justify-end gap-4"><button onClick={() => { setStep(1); onClose(); }} className="px-8 py-3 text-gray-400 font-black hover:text-gray-900 text-sm uppercase tracking-widest">Discard</button><button disabled={loading || !title || !description} onClick={handleNext} className="px-10 py-4 bg-gray-900 text-white font-black rounded-2xl hover:bg-black shadow-2xl disabled:opacity-30 flex items-center gap-3 text-sm active:scale-95 transition-all">{loading ? 'Processing...' : (step === 1 ? 'Analyze Impact' : 'Launch to Network')}<ChevronRight size={20} /></button></div>
      </div>
    </div>
  );
};

const App = () => (
  <Router>
    <AppContent />
  </Router>
);

export default App;

