// Sub-component for Create Modal
const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: any) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    if (isOpen) { 
        setType(initialType || ImpactType.PROBLEM); 
        setTitle(prefilledTitle || ''); 
        setStep(1);
    }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try { 
          const result = await analyzeProblem(description); 
          setAiAnalysis(result); 
          setStep(2); 
      } catch (e) { 
          setStep(2); 
      } finally { 
          setLoading(false); 
      }
    } else {
      onSubmit({ title, description, type, tags: aiAnalysis?.tags || ['community'] });
      setTitle(''); setDescription(''); setAiAnalysis(null); 
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-950/40 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] border border-gray-100">
        <div className="p-6 border-b border-gray-50 flex justify-between items-center bg-gray-50/50">
            <h3 className="text-lg font-black text-gray-900 tracking-tight flex items-center gap-2">
                {step === 1 ? <PlusCircle size={20} className="text-emerald-500" /> : <Sparkles size={20} className="text-indigo-500" />}
                {step === 1 ? 'New Action' : 'Impact Logic'}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-900 transition-colors"><X size={20} /></button>
        </div>
        <div className="p-8 overflow-y-auto space-y-6">
          {step === 1 ? (
            <>
              <div>
                <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-3">Classification</label>
                <div className="grid grid-cols-2 gap-3">
                    {[ 
                        { id: ImpactType.PROBLEM, label: 'Report Issue', color: 'text-amber-600', active: 'bg-amber-50 border-amber-200 shadow-inner' }, 
                        { id: ImpactType.INITIATIVE, label: 'New Project', color: 'text-emerald-600', active: 'bg-emerald-50 border-emerald-200 shadow-inner' } 
                    ].map(btn => ( 
                        <button key={btn.id} onClick={() => setType(btn.id as any)} className={`py-3.5 rounded-xl text-xs font-black border-2 transition-all ${type === btn.id ? btn.active + ' ' + btn.color : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'}`}>{btn.label}</button> 
                    ))}
                </div>
              </div>
              <div>
                <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-2">Subject</label>
                <input value={title} onChange={e => setTitle(e.target.value)} className="w-full px-5 py-3.5 rounded-xl bg-gray-50 border border-gray-100 focus:bg-white focus:border-gray-900 outline-none font-bold text-gray-900" placeholder="e.g. Broken Water Pipe" />
              </div>
              <div>
                <label className="block text-[9px] font-black text-gray-400 uppercase tracking-widest mb-2">Context</label>
                <textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full px-5 py-3.5 rounded-xl bg-gray-50 border border-gray-100 focus:bg-white focus:border-gray-900 outline-none h-32 resize-none font-medium text-sm" placeholder="Explain the situation and the impact..." />
              </div>
            </>
          ) : (
            <div className="space-y-6 animate-fade-in">
              <div className="bg-gray-900 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden">
                <div className="relative z-10">
                    <div className="flex items-center gap-2 mb-3">
                        <Shield className="text-emerald-400" size={18} />
                        <span className="font-black text-[9px] uppercase tracking-[0.2em]">Risk Analysis</span>
                    </div>
                    <p className="text-gray-300 font-medium text-sm leading-relaxed mb-4">{aiAnalysis?.summary || "Analyzing node parameters..."}</p>
                    <div className="flex gap-2 flex-wrap">
                        {aiAnalysis?.tags?.map((tag: string) => ( 
                            <span key={tag} className="text-[8px] font-black px-2 py-1 bg-white/10 rounded-lg uppercase tracking-widest">#{tag}</span> 
                        ))}
                    </div>
                </div>
              </div>
              {aiAnalysis?.suggestedInitiatives && aiAnalysis.suggestedInitiatives.length > 0 && ( 
                <div>
                    <h4 className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-3">AI Recommendations</h4>
                    <div className="space-y-3">
                        {aiAnalysis.suggestedInitiatives.map((si: any, i: number) => ( 
                            <div key={i} className="p-4 border border-gray-100 rounded-2xl bg-gray-50/50 hover:bg-white hover:border-gray-900 transition-all cursor-pointer">
                                <div className="flex justify-between items-start mb-1.5">
                                    <div className="font-bold text-gray-900 text-xs">{si.title}</div>
                                    <span className="text-[8px] font-black uppercase text-emerald-500">{si.impactLevel}</span>
                                </div>
                                <div className="text-gray-500 text-[10px] font-medium leading-relaxed">{si.description}</div>
                            </div> 
                        ))}
                    </div>
                </div> 
              )}
            </div>
          )}
        </div>
        <div className="p-6 border-t border-gray-50 bg-gray-50/50 flex justify-end gap-3">
            <button onClick={onClose} className="px-6 py-2.5 text-gray-400 font-black text-[10px] uppercase tracking-widest">Discard</button>
            <button 
                disabled={loading || !title || !description} 
                onClick={handleNext} 
                className="px-8 py-3 bg-gray-900 text-white font-black rounded-xl hover:bg-black shadow-lg disabled:opacity-30 flex items-center gap-2 text-[11px] uppercase tracking-widest transition-all active:scale-95"
            >
                {loading ? 'Synthesizing...' : (step === 1 ? 'Analyze' : 'Broadcast')}
                <ChevronRight size={14} />
            </button>
        </div>
      </div>
    </div>
  );
};

// Main App Component
const ImpactHack = () => {
  const [entries, setEntries] = useState<ImpactEntry[]>(INITIAL_ENTRIES);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [joinedIds, setJoinedIds] = useState<Set<string>>(new Set());
  const [view, setView] = useState<'feed' | 'dashboard'>('feed');
  const [createConfig, setCreateConfig] = useState<{type?: ImpactType, title?: string, problemId?: string}>({});
  const [userStats, setUserStats] = useState<UserStats>({
    problemsReported: 0, initiativesJoined: 0, milestonesReached: 0, totalKarma: 150
  });

  const userRegion = "Central Node";

  const handleVote = (id: string, delta: number) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, votes: e.votes + delta } : e));
  };

  const handleJoin = (id: string) => {
    setJoinedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
        setUserStats(s => ({ ...s, initiativesJoined: Math.max(0, s.initiativesJoined - 1) }));
      } else {
        next.add(id);
        setUserStats(s => ({ ...s, initiativesJoined: s.initiativesJoined + 1, totalKarma: s.totalKarma + 50 }));
      }
      return next;
    });
  };

  const handleToggleMilestone = (milestoneId: string) => {
    if (!selectedId) return;
    setEntries(prev => prev.map(entry => {
      if (entry.id !== selectedId || !entry.milestones) return entry;
      const mIdx = entry.milestones.findIndex(m => m.id === milestoneId);
      const wasCompleted = entry.milestones[mIdx].isCompleted;
      if (!wasCompleted) setUserStats(s => ({ ...s, milestonesReached: s.milestonesReached + 1, totalKarma: s.totalKarma + 25 }));
      return {
        ...entry,
        milestones: entry.milestones.map(m => m.id === milestoneId ? { ...m, isCompleted: !m.isCompleted } : m)
      };
    }));
  };

  const handlePost = async (partial: Partial<ImpactEntry>) => {
    const newId = Date.now().toString();
    let milestones: Milestone[] = [];
    if (partial.type === ImpactType.INITIATIVE) {
      milestones = await generateMilestones(partial.title!, partial.description!);
    }

    const newEntry: ImpactEntry = {
      id: newId, 
      type: partial.type!, 
      title: partial.title!, 
      description: partial.description!,
      author: 'you', 
      location: `Near ${userRegion}`, 
      region: userRegion, 
      timestamp: 'Just now',
      votes: 1, 
      followersCount: 1, 
      tags: partial.tags || ['community'], 
      comments: [],
      participantsCount: partial.type === ImpactType.INITIATIVE ? 1 : 0,
      milestones: partial.type === ImpactType.INITIATIVE ? milestones : undefined,
      status: 'active', 
      linkedProblemId: createConfig.problemId
    };

    setEntries(prev => {
      let updated = [newEntry, ...prev];
      if (createConfig.problemId) {
        updated = updated.map(e => (e.id === createConfig.problemId) ? { ...e, linkedInitiativeIds: [...(e.linkedInitiativeIds || []), newId] } : e);
      }
      return updated;
    });

    if (partial.type === ImpactType.PROBLEM) {
        setUserStats(s => ({ ...s, problemsReported: s.problemsReported + 1, totalKarma: s.totalKarma + 100 }));
    }

    setIsModalOpen(false); 
    setCreateConfig({}); 
    setSelectedId(newId);
    if (partial.type === ImpactType.INITIATIVE) handleJoin(newId);
  };

  const selectedEntry = entries.find(e => e.id === selectedId);

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 font-inter">
      <nav className="sticky top-0 z-40 bg-white/80 backdrop-blur-xl border-b border-gray-100 h-20 flex items-center px-4 sm:px-12">
        <div className="max-w-7xl mx-auto w-full flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => { setSelectedId(null); setView('feed'); }}>
            <div className="w-10 h-10 bg-gray-900 rounded-xl flex items-center justify-center shadow-lg group-hover:scale-105 transition-all">
              <Zap className="text-emerald-400" size={20} strokeWidth={3} />
            </div>
            <div className="hidden sm:block">
              <span className="text-xl font-black text-gray-900 tracking-tighter block leading-none">ImpactHack</span>
              <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest mt-0.5 block">Community OS</span>
            </div>
          </div>
          <div className="flex items-center gap-3 sm:gap-6">
             <button onClick={() => { setCreateConfig({}); setIsModalOpen(true); }} className="bg-gray-900 text-white px-5 py-2.5 rounded-xl font-black text-[11px] uppercase tracking-wider hover:bg-black transition-all shadow-xl active:scale-95 flex items-center gap-2">
               <PlusCircle size={16} /> <span className="hidden md:inline">File Report</span>
             </button>
             <button onClick={() => { setView('dashboard'); setSelectedId(null); }} className={`relative p-2.5 rounded-xl border transition-all ${view === 'dashboard' ? 'bg-gray-900 text-white border-gray-900' : 'bg-white text-gray-400 border-gray-200'}`}>
                <Layout size={20} />
             </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl mx-auto w-full flex flex-col md:flex-row gap-10 p-4 lg:p-12">
        <aside className="hidden md:flex flex-col w-60 shrink-0 gap-6 sticky top-32 h-fit">
          <nav className="space-y-1">
            <button onClick={() => { setView('feed'); setSelectedId(null); }} className={`w-full flex items-center gap-3 px-4 py-3.5 font-black text-xs uppercase tracking-widest rounded-xl transition-all ${view === 'feed' && !selectedId ? 'bg-gray-900 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-900'}`}>
              <Home size={18} /> Action Feed
            </button>
            <button onClick={() => { setView('dashboard'); setSelectedId(null); }} className={`w-full flex items-center gap-3 px-4 py-3.5 font-black text-xs uppercase tracking-widest rounded-xl transition-all ${view === 'dashboard' ? 'bg-gray-900 text-white shadow-xl' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-900'}`}>
              <Layout size={18} /> My Impact
            </button>
          </nav>

          <div className="bg-white rounded-3xl p-6 border border-gray-100 shadow-sm">
             <div className="flex items-center gap-2 mb-4">
                <Heart size={14} className="text-red-500" fill="currentColor" />
                <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">Popular Focus</span>
             </div>
             <div className="space-y-3">
                {['#Safety', '#GreenCity', '#Roads'].map(tag => (
                   <div key={tag} className="text-xs font-bold text-gray-500 hover:text-gray-900 cursor-pointer">{tag}</div>
                ))}
             </div>
          </div>
        </aside>

        <div className="flex-1 min-w-0">
          {selectedId && selectedEntry ? (
            <div className="max-w-3xl mx-auto animate-fade-in pb-24">
              <button onClick={() => setSelectedId(null)} className="flex items-center gap-2 text-gray-400 hover:text-gray-900 mb-8 font-black text-[10px] uppercase tracking-[0.2em] transition-all">
                <X size={14} /> Back to Hub
              </button>
              <div className="bg-white rounded-[2.5rem] border border-gray-100 shadow-xl p-8 md:p-12">
                <div className="flex items-center justify-between mb-8">
                  <span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${selectedEntry.type === ImpactType.PROBLEM ? 'bg-amber-50 text-amber-700 border-amber-100' : 'bg-emerald-50 text-emerald-700 border-emerald-100'}`}>{selectedEntry.type}</span>
                  <div className="flex items-center gap-4 bg-gray-50 px-4 py-2 rounded-2xl border border-gray-100">
                    <button onClick={() => handleVote(selectedEntry.id, 1)} className="text-gray-400 hover:text-gray-900"><ArrowBigUp size={24} /></button>
                    <span className="font-black text-gray-900 text-xl tracking-tighter">{selectedEntry.votes}</span>
                    <button onClick={() => handleVote(selectedEntry.id, -1)} className="text-gray-400 hover:text-gray-900"><ArrowBigDown size={24} /></button>
                  </div>
                </div>
                <h1 className="text-4xl font-black text-gray-900 mb-6 tracking-tight">{selectedEntry.title}</h1>
                <p className="text-xl text-gray-600 leading-relaxed font-medium mb-12">{selectedEntry.description}</p>
                {selectedEntry.type === ImpactType.INITIATIVE && (
                  <div className="mb-12">
                    <div className="flex items-center justify-between gap-4 mb-8">
                       <h3 className="text-2xl font-black text-gray-900 tracking-tight">Project Roadmap</h3>
                       <button onClick={() => handleJoin(selectedEntry.id)} className={`px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all flex items-center gap-2 ${joinedIds.has(selectedEntry.id) ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-emerald-600 text-white shadow-lg hover:bg-emerald-700'}`}>
                         {joinedIds.has(selectedEntry.id) ? <UserCheck size={18} /> : <UserPlus size={18} />} {joinedIds.has(selectedEntry.id) ? 'Joined' : 'Join Action'}
                       </button>
                    </div>
                    <div className="bg-gray-50 p-8 rounded-[2rem] border border-gray-100">
                      <MilestoneTracker milestones={selectedEntry.milestones || []} onToggle={handleToggleMilestone} />
                    </div>
                  </div>
                )}
                {selectedEntry.type === ImpactType.PROBLEM && (
                  <div className="bg-amber-50/30 rounded-[2rem] p-8 border border-amber-100 mb-12 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                    <div>
                      <h3 className="text-xl font-black text-gray-900 tracking-tight flex items-center gap-2 mb-1"><Lightbulb className="text-amber-500" size={24} /> Take Action</h3>
                      <p className="text-gray-500 text-sm font-medium">Ready to turn this report into a solution?</p>
                    </div>
                    <button onClick={() => { setCreateConfig({ type: ImpactType.INITIATIVE, title: `Fix: ${selectedEntry.title}`, problemId: selectedEntry.id }); setIsModalOpen(true); }} className="bg-gray-900 text-white px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest shadow-lg hover:bg-black transition-all flex items-center gap-2 active:scale-95"><Sparkles size={16} /> Propose Solution</button>
                  </div>
                )}
              </div>
            </div>
          ) : view === 'dashboard' ? (
            <DashboardView stats={userStats} entries={entries} joinedIds={joinedIds} />
          ) : (
            <div className="space-y-8 max-w-2xl mx-auto py-6 px-4 animate-fade-in">
              <div className="bg-gray-900 rounded-[2.5rem] p-10 text-white relative overflow-hidden shadow-2xl">
                <div className="relative z-10">
