type ViewState = 'home' | 'initiatives' | 'impact' | 'feed' | 'milestones';

const ImpactHack = () => {
  const [entries, setEntries] = useState<ImpactEntry[]>(INITIAL_ENTRIES);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [joinedIds, setJoinedIds] = useState<Set<string>>(new Set(['2']));
  const [view, setView] = useState<ViewState>('home');
  const [createConfig, setCreateConfig] = useState<{type?: ImpactType, title?: string, problemId?: string}>({});
  const [userStats, setUserStats] = useState<UserStats>({
    problemsReported: 1, initiativesJoined: 1, milestonesReached: 1, totalKarma: 450
  });

  const handleVote = (id: string, delta: number) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, votes: e.votes + delta } : e));
  };

  const handleJoin = (id: string) => {
    setJoinedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
        setUserStats(s => ({ ...s, initiativesJoined: Math.max(0, s.initiativesJoined - 1) }));
      } else {
        next.add(id);
        setUserStats(s => ({ ...s, initiativesJoined: s.initiativesJoined + 1, totalKarma: s.totalKarma + 50 }));
      }
      return next;
    });
  };

  const handleToggleMilestone = (milestoneId: string) => {
    if (!selectedId) return;
    setEntries(prev => prev.map(entry => {
      if (entry.id !== selectedId || !entry.milestones) return entry;
      const milestone = entry.milestones.find(m => m.id === milestoneId);
      if (!milestone) return entry;

      const becomingCompleted = !milestone.isCompleted;
      if (becomingCompleted) {
        setUserStats(s => ({ ...s, milestonesReached: s.milestonesReached + 1, totalKarma: s.totalKarma + 25 }));
      } else {
        setUserStats(s => ({ ...s, milestonesReached: Math.max(0, s.milestonesReached - 1), totalKarma: s.totalKarma - 25 }));
      }

      return {
        ...entry,
        milestones: entry.milestones.map(m => m.id === milestoneId ? { ...m, isCompleted: !m.isCompleted } : m)
      };
    }));
  };

  const handlePost = async (partial: Partial<ImpactEntry>) => {
    const newId = Date.now().toString();
    let milestones: Milestone[] = [];
    if (partial.type === ImpactType.INITIATIVE) {
      milestones = await generateMilestones(partial.title!, partial.description!);
    }

    const newEntry: ImpactEntry = {
      id: newId, 
      type: partial.type!, 
      title: partial.title!, 
      description: partial.description!,
      author: 'you', 
      location: `Local Area`, 
      region: "Central", 
      timestamp: 'Just now',
      votes: 1, 
      followersCount: 1, 
      tags: partial.tags || ['community'], 
      comments: [],
      participantsCount: partial.type === ImpactType.INITIATIVE ? 1 : 0,
      milestones: partial.type === ImpactType.INITIATIVE ? milestones : undefined,
      status: 'active', 
      linkedProblemId: createConfig.problemId
    };

    setEntries(prev => {
      let updated = [newEntry, ...prev];
      if (createConfig.problemId) {
        updated = updated.map(e => (e.id === createConfig.problemId) ? { ...e, linkedInitiativeIds: [...(e.linkedInitiativeIds || []), newId] } : e);
      }
      return updated;
    });

    if (partial.type === ImpactType.PROBLEM) {
        setUserStats(s => ({ ...s, problemsReported: s.problemsReported + 1, totalKarma: s.totalKarma + 100 }));
    }

    setIsModalOpen(false); 
    setCreateConfig({}); 
    setSelectedId(newId);
    if (partial.type === ImpactType.INITIATIVE) handleJoin(newId);
  };

  const selectedEntry = entries.find(e => e.id === selectedId);

  // Navigation Items
  const navItems = [
    { id: 'home', icon: <Home size={18} />, label: 'Home' },
    { id: 'initiatives', icon: <Rocket size={18} />, label: 'Initiatives available' },
    { id: 'impact', icon: <Award size={18} />, label: 'Your impact' },
    { id: 'feed', icon: <Layout size={18} />, label: 'Reports and solutions feed' },
    { id: 'milestones', icon: <CheckCircle size={18} />, label: 'Milestones achieved' },
  ];

  const filteredEntries = useMemo(() => {
    if (view === 'initiatives') return entries.filter(e => e.type === ImpactType.INITIATIVE);
    return entries;
  }, [entries, view]);

  return (
    <div className="min-h-screen flex bg-[#fcfcfd] font-inter">
      {/* Sidebar Navigation */}
      <aside className="w-72 bg-white border-r border-gray-100 flex flex-col sticky top-0 h-screen shrink-0 overflow-y-auto">
        <div className="p-8">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => { setSelectedId(null); setView('home'); }}>
            <div className="w-10 h-10 bg-gradient-to-tr from-emerald-500 to-blue-600 rounded-xl flex items-center justify-center shadow-lg group-hover:scale-105 transition-all">
              <Zap className="text-white" size={20} strokeWidth={3} />
            </div>
            <div>
              <span className="text-xl font-black text-gray-900 tracking-tighter block leading-none">ImpactHack</span>
              <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest mt-0.5 block">Community OS</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-2">
          {navItems.map(item => (
            <button 
              key={item.id} 
              onClick={() => { setView(item.id as any); setSelectedId(null); }} 
              className={`w-full flex items-center gap-4 px-5 py-4 font-black text-xs uppercase tracking-widest rounded-2xl transition-all duration-300 ${
                view === item.id && !selectedId 
                  ? 'bg-gradient-to-r from-gray-900 to-gray-800 text-white shadow-xl shadow-gray-200 translate-x-1' 
                  : 'text-gray-400 hover:bg-gray-50 hover:text-gray-900'
              }`}
            >
              <span className={view === item.id && !selectedId ? 'text-emerald-400' : ''}>{item.icon}</span>
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-6">
          <button 
            onClick={() => { setCreateConfig({}); setIsModalOpen(true); }}
            className="w-full bg-gradient-to-br from-rose-500 to-orange-500 text-white p-5 rounded-3xl font-black text-[11px] uppercase tracking-widest hover:brightness-110 transition-all shadow-xl shadow-rose-100 active:scale-95 flex items-center justify-center gap-2"
          >
            <PlusCircle size={18} /> File Report
          </button>
        </div>
      </aside>

      <main className="flex-1 min-w-0 p-8 lg:p-12">
        <div className="max-w-5xl mx-auto">
          {selectedId && selectedEntry ? (
            <DetailView 
              entry={selectedEntry} 
              isJoined={joinedIds.has(selectedEntry.id)} 
              onVote={handleVote} 
              onToggleMilestone={handleToggleMilestone}
              onJoin={handleJoin}
              onBack={() => setSelectedId(null)}
              onPropose={() => { 
                setCreateConfig({ type: ImpactType.INITIATIVE, title: `Fix: ${selectedEntry.title}`, problemId: selectedEntry.id }); 
                setIsModalOpen(true); 
              }}
            />
          ) : (
            <div className="animate-fade-in space-y-12">
              {view === 'home' && (
                <HomeView stats={userStats} entries={entries} onNavigate={setView} setDetail={setSelectedId} />
              )}

              {view === 'impact' && (
                <ImpactDashboard stats={userStats} entries={entries} joinedIds={joinedIds} />
              )}

              {view === 'milestones' && (
                <MilestonesHall entries={entries} joinedIds={joinedIds} />
              )}

              {(view === 'initiatives' || view === 'feed') && (
                <div className="space-y-8">
                  <div className={`p-10 rounded-[2.5rem] text-white relative overflow-hidden shadow-2xl ${
                    view === 'initiatives' ? 'bg-gradient-to-br from-emerald-600 to-teal-800' : 'bg-gradient-to-br from-indigo-600 to-blue-800'
                  }`}>
                    <div className="relative z-10">
                      <h2 className="text-5xl font-black tracking-tighter mb-3 leading-none">
                        {view === 'initiatives' ? 'Initiatives' : 'Reports & Solutions'}
                      </h2>
                      <p className="text-white/70 font-medium text-lg max-w-sm">
                        {view === 'initiatives' ? 'Join forces with neighbors to solve local challenges.' : 'The heartbeat of community transparency.'}
                      </p>
                    </div>
                    <div className="absolute -right-12 -bottom-12 opacity-10">
                      {view === 'initiatives' ? <Rocket size={240} /> : <Globe size={240} />}
                    </div>
                  </div>
                  <div className="grid gap-6">
                    {filteredEntries.map(entry => (
                      <ImpactCard 
                        key={entry.id} 
                        entry={entry} 
                        onVote={handleVote} 
                        onClick={setSelectedId} 
                        onJoin={handleJoin} 
                        isJoined={joinedIds.has(entry.id)} 
                      />
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </main>

      <CreateModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSubmit={handlePost} 
        initialType={createConfig.type} 
        prefilledTitle={createConfig.title} 
      />
    </div>
  );
};

