            key={m.id} 
            className={`flex items-start gap-6 p-6 rounded-[2rem] border-2 transition-all duration-500 ${
              m.isCompleted 
                ? 'bg-white border-emerald-100 shadow-xl shadow-emerald-50 opacity-80' 
                : 'bg-white border-gray-100 hover:border-blue-200 shadow-sm'
            }`}
          >
            <button 
              onClick={() => onToggle(m.id)}
