const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: any) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    if (isOpen) { 
        setType(initialType || ImpactType.PROBLEM); 
        setTitle(prefilledTitle || ''); 
        setStep(1);
    }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try { 
          const result = await analyzeProblem(description); 
          setAiAnalysis(result); 
          setStep(2); 
      } catch (e) { 
          setStep(2); 
      } finally { 
          setLoading(false); 
      }
    } else {
      onSubmit({ title, description, type, tags: aiAnalysis?.tags || ['community'] });
      setTitle(''); setDescription(''); setAiAnalysis(null); 
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-950/40 backdrop-blur-md p-4 animate-fade-in">
      <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-xl overflow-hidden flex flex-col max-h-[90vh] border border-white/20">
        <div className="p-8 border-b border-gray-50 flex justify-between items-center bg-gray-50/50">
            <h3 className="text-2xl font-black text-gray-900 tracking-tight flex items-center gap-3">
                {step === 1 ? (
                  type === ImpactType.PROBLEM ? <AlertTriangle size={28} className="text-rose-500" /> : <Rocket size={28} className="text-emerald-500" />
                ) : <Sparkles size={28} className="text-indigo-500" />}
                {step === 1 ? (type === ImpactType.PROBLEM ? 'Report Issue' : 'Make Initiative') : 'Impact Synthesis'}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-900 transition-colors bg-white w-10 h-10 rounded-full flex items-center justify-center shadow-sm border border-gray-100"><X size={20} /></button>
        </div>
        <div className="p-10 overflow-y-auto space-y-8">
          {step === 1 ? (
            <>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">Select Node Type</label>
                <div className="grid grid-cols-2 gap-4">
                    {[ 
                        { id: ImpactType.PROBLEM, label: 'Report Issue', color: 'text-rose-600', active: 'bg-rose-50 border-rose-200 shadow-inner ring-2 ring-rose-100' }, 
                        { id: ImpactType.INITIATIVE, label: 'New Project', color: 'text-emerald-600', active: 'bg-emerald-50 border-emerald-200 shadow-inner ring-2 ring-emerald-100' } 
                    ].map(btn => ( 
                        <button key={btn.id} onClick={() => setType(btn.id as any)} className={`py-6 rounded-[2rem] text-xs font-black border-2 transition-all duration-300 ${type === btn.id ? btn.active + ' ' + btn.color : 'bg-white border-gray-100 text-gray-400 hover:border-gray-300'}`}>{btn.label}</button> 
                    ))}
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Action Title</label>
                <input value={title} onChange={e => setTitle(e.target.value)} className="w-full px-6 py-5 rounded-2xl bg-gray-50 border border-gray-100 focus:bg-white focus:border-gray-900 focus:ring-4 focus:ring-gray-50 outline-none font-black text-gray-900 text-lg transition-all" placeholder="What's happening?" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Community Context</label>
                <textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full px-6 py-5 rounded-2xl bg-gray-50 border border-gray-100 focus:bg-white focus:border-gray-900 focus:ring-4 focus:ring-gray-50 outline-none h-40 resize-none font-medium text-lg transition-all" placeholder="Describe the impact and the potential solution..." />
              </div>
            </>
          ) : (
            <div className="space-y-8 animate-fade-in">
              <div className="bg-gradient-to-br from-indigo-600 to-blue-800 rounded-[2.5rem] p-10 text-white shadow-2xl relative overflow-hidden">
                <div className="relative z-10">
                    <div className="flex items-center gap-3 mb-6">
                        <Shield className="text-blue-300" size={28} />
                        <span className="font-black text-xs uppercase tracking-[0.2em] text-blue-200">System Synthesis</span>
                    </div>
                    <p className="text-white text-xl font-medium leading-relaxed mb-8">{aiAnalysis?.summary || "Analyzing neighborhood parameters..."}</p>
                    <div className="flex gap-3 flex-wrap">
                        {aiAnalysis?.tags?.map((tag: string) => ( 
                            <span key={tag} className="text-[10px] font-black px-4 py-2 bg-white/10 rounded-xl uppercase tracking-widest border border-white/10 shadow-inner">#{tag}</span> 
                        ))}
                    </div>
                </div>
                <Sparkles className="absolute -right-10 -bottom-10 text-white/5" size={240} />
              </div>
            </div>
          )}
        </div>
        <div className="p-8 border-t border-gray-50 bg-gray-50/50 flex justify-end gap-4">
            <button onClick={onClose} className="px-8 py-3 text-gray-400 font-black text-[11px] uppercase tracking-widest hover:text-gray-900 transition-colors">Abort</button>
            <button 
                disabled={loading || !title || !description} 
                onClick={handleNext} 
                className="px-10 py-4 bg-gray-900 text-white font-black rounded-2xl hover:bg-black shadow-2xl shadow-gray-200 disabled:opacity-30 flex items-center gap-3 text-[11px] uppercase tracking-widest transition-all active:scale-95"
            >
                {loading ? (
                  <>
                    <Zap className="animate-spin text-emerald-400" size={16} />
                    Synthesizing...
                  </>
                ) : (
                  <>
                    {step === 1 ? 'Initiate Analysis' : 'Final Broadcast'}
                    <ChevronRight size={16} />
                  </>
                )}
            </button>
        </div>
      </div>
    </div>
  );
};

