type ViewState = 'home' | 'initiatives' | 'impact' | 'feed' | 'milestones';

const ImpactHack = () => {
  const [entries, setEntries] = useState<ImpactEntry[]>(INITIAL_ENTRIES);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [joinedIds, setJoinedIds] = useState<Set<string>>(new Set(['2']));
  const [view, setView] = useState<ViewState>('home');
  const [createConfig, setCreateConfig] = useState<{type?: ImpactType, title?: string, problemId?: string}>({});
  const [userStats, setUserStats] = useState<UserStats>({
    problemsReported: 1, initiativesJoined: 1, milestonesReached: 1, totalKarma: 450
  });

  const handleVote = (id: string, delta: number) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, votes: e.votes + delta } : e));
  };

  const handleJoin = (id: string) => {
    setJoinedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
        setUserStats(s => ({ ...s, initiativesJoined: Math.max(0, s.initiativesJoined - 1) }));
      } else {
        next.add(id);
        setUserStats(s => ({ ...s, initiativesJoined: s.initiativesJoined + 1, totalKarma: s.totalKarma + 50 }));
      }
      return next;
    });
  };

  const handleToggleMilestone = (milestoneId: string) => {
    if (!selectedId) return;
    setEntries(prev => prev.map(entry => {
      if (entry.id !== selectedId || !entry.milestones) return entry;
      const milestone = entry.milestones.find(m => m.id === milestoneId);
      if (!milestone) return entry;

      const becomingCompleted = !milestone.isCompleted;
      if (becomingCompleted) {
        setUserStats(s => ({ ...s, milestonesReached: s.milestonesReached + 1, totalKarma: s.totalKarma + 25 }));
      } else {
        setUserStats(s => ({ ...s, milestonesReached: Math.max(0, s.milestonesReached - 1), totalKarma: s.totalKarma - 25 }));
      }

      return {
        ...entry,
        milestones: entry.milestones.map(m => m.id === milestoneId ? { ...m, isCompleted: !m.isCompleted } : m)
      };
    }));
  };

  const handlePost = async (partial: Partial<ImpactEntry>) => {
    const newId = Date.now().toString();
    let milestones: Milestone[] = [];
    if (partial.type === ImpactType.INITIATIVE) {
      milestones = await generateMilestones(partial.title!, partial.description!);
    }

    const newEntry: ImpactEntry = {
      id: newId, 
      type: partial.type!, 
      title: partial.title!, 
      description: partial.description!,
      author: 'you', 
      location: `Local Area`, 
      region: "Central", 
      timestamp: 'Just now',
      votes: 1, 
      followersCount: 1, 
      tags: partial.tags || ['community'], 
      comments: [],
      participantsCount: partial.type === ImpactType.INITIATIVE ? 1 : 0,
      milestones: partial.type === ImpactType.INITIATIVE ? milestones : undefined,
      status: 'active', 
      linkedProblemId: createConfig.problemId,
    };

    setEntries(prev => {
      let updated = [newEntry, ...prev];
      if (createConfig.problemId) {
        updated = updated.map(e => (e.id === createConfig.problemId) ? { ...e, linkedInitiativeIds: [...(e.linkedInitiativeIds || []), newId] } : e);
      }
      return updated;
    });

    if (partial.type === ImpactType.PROBLEM) {
        setUserStats(s => ({ ...s, problemsReported: s.problemsReported + 1, totalKarma: s.totalKarma + 100 }));
    }

    setIsModalOpen(false); 
    setCreateConfig({}); 
    setSelectedId(newId);
    if (partial.type === ImpactType.INITIATIVE) handleJoin(newId);
  };

  const selectedEntry = entries.find(e => e.id === selectedId);

  // Navigation Items
  const navItems = [
    { id: 'home', icon: <Home size={20} />, label: 'Home', color: 'text-indigo-500' },
    { id: 'initiatives', icon: <Rocket size={20} />, label: 'Initiatives', color: 'text-emerald-500' },
    { id: 'impact', icon: <Award size={20} />, label: 'Your impact', color: 'text-amber-500' },
    { id: 'feed', icon: <Layout size={20} />, label: 'Action Feed', color: 'text-rose-500' },
    { id: 'milestones', icon: <CheckCircle size={20} />, label: 'Milestones', color: 'text-cyan-500' },
  ];

  const filteredEntries = useMemo(() => {
    if (view === 'initiatives') return entries.filter(e => e.type === ImpactType.INITIATIVE);
    return entries;
  }, [entries, view]);

  return (
    <div className="min-h-screen flex font-inter">
      {/* Sidebar Navigation */}
      <aside className="w-80 glass-sidebar flex flex-col sticky top-0 h-screen shrink-0 overflow-hidden shadow-2xl z-20">
        <div className="p-8">
          <div className="flex items-center gap-4 cursor-pointer group" onClick={() => { setSelectedId(null); setView('home'); }}>
            <div className="w-12 h-12 bg-gradient-to-tr from-indigo-600 via-emerald-500 to-amber-400 rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-all duration-500 group-hover:rotate-6">
              <Zap className="text-white fill-current" size={24} strokeWidth={2.5} />
            </div>
            <div>
              <span className="text-2xl font-black text-gray-900 tracking-tighter block leading-none">ImpactHack</span>
              <div className="flex items-center gap-1 mt-1">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">Live Hub</span>
              </div>
            </div>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-2 overflow-y-auto">
          <div className="px-5 py-2 text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-2 opacity-50">Main Deck</div>
          {navItems.map(item => (
            <button 
              key={item.id} 
              onClick={() => { setView(item.id as any); setSelectedId(null); }} 
              className={`w-full flex items-center gap-4 px-5 py-4 font-black text-[12px] uppercase tracking-wider rounded-2xl transition-all duration-500 relative group ${
                view === item.id && !selectedId 
                  ? 'bg-gray-900 text-white shadow-2xl shadow-gray-400 translate-x-2' 
                  : 'text-gray-500 hover:bg-white hover:text-gray-900 hover:translate-x-1'
              }`}
            >
              <span className={`transition-all duration-500 group-hover:scale-110 ${view === item.id && !selectedId ? item.color : 'text-gray-400'}`}>
                {item.icon}
              </span>
              {item.label}
              {view === item.id && !selectedId && (
                <div className="absolute left-0 top-1/4 bottom-1/4 w-1 bg-emerald-400 rounded-r-full"></div>
              )}
            </button>
          ))}
        </nav>

        {/* Sidebar Action Buttons */}
        <div className="p-6 space-y-3 bg-gradient-to-b from-transparent to-white/30 border-t border-white/50">
