          >
            <div className="bg-white/20 p-2 rounded-xl group-hover:rotate-12 transition-transform"><AlertTriangle size={16} /></div>
            File Report
          </button>
        </div>
      </aside>

      <main className="flex-1 min-w-0 p-8 lg:p-12 overflow-y-auto relative z-10">
        <div className="max-w-5xl mx-auto">
          {selectedId && selectedEntry ? (
            <DetailView 
              entry={selectedEntry} 
              isJoined={joinedIds.has(selectedEntry.id)} 
              onVote={handleVote} 
              onToggleMilestone={handleToggleMilestone}
              onJoin={handleJoin}
              onBack={() => setSelectedId(null)}
              onPropose={() => { 
                setCreateConfig({ type: ImpactType.INITIATIVE, title: `Fix: ${selectedEntry.title}`, problemId: selectedEntry.id }); 
                setIsModalOpen(true); 
              }}
            />
          ) : (
            <div className="animate-fade-in space-y-12">
              {view === 'home' && (
                <HomeView stats={userStats} entries={entries} onNavigate={setView} setDetail={setSelectedId} />
              )}

              {view === 'impact' && (
                <ImpactDashboard stats={userStats} entries={entries} joinedIds={joinedIds} />
              )}

              {view === 'milestones' && (
                <MilestonesHall entries={entries} joinedIds={joinedIds} />
              )}

              {(view === 'initiatives' || view === 'feed') && (
                <div className="space-y-8">
                  <div className={`p-12 rounded-[3.5rem] text-white relative overflow-hidden shadow-2xl ${
                    view === 'initiatives' ? 'bg-gradient-to-br from-emerald-500 via-teal-600 to-blue-600' : 'bg-gradient-to-br from-indigo-500 via-purple-600 to-rose-500'
                  }`}>
                    <div className="relative z-10">
                      <div className="flex items-center gap-3 mb-4">
                         <div className="w-10 h-10 rounded-xl bg-white/20 backdrop-blur-md flex items-center justify-center">
