const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: any) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    if (isOpen) { 
        setType(initialType || ImpactType.PROBLEM); 
        setTitle(prefilledTitle || ''); 
        setStep(1);
    }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try { 
          const result = await analyzeProblem(description); 
          setAiAnalysis(result); 
          setStep(2); 
      } catch (e) { 
          setStep(2); 
      } finally { 
          setLoading(false); 
      }
    } else {
      onSubmit({ title, description, type, tags: aiAnalysis?.tags || ['community'] });
      setTitle(''); setDescription(''); setAiAnalysis(null); 
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-gray-950/60 backdrop-blur-xl p-4 animate-fade-in">
      <div className="bg-white rounded-[4rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.3)] w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh] border border-white/20">
        <div className="p-10 border-b border-gray-50 flex justify-between items-center bg-gray-50/50">
            <h3 className="text-3xl font-black text-gray-900 tracking-tight flex items-center gap-4">
                {step === 1 ? (
                  type === ImpactType.PROBLEM ? <AlertTriangle size={36} className="text-rose-500" /> : <Rocket size={36} className="text-emerald-500" />
                ) : <Sparkles size={36} className="text-indigo-500" />}
                {step === 1 ? (type === ImpactType.PROBLEM ? 'Report Gaps' : 'Initiate Project') : 'AI Synthesis'}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-900 transition-all bg-white w-12 h-12 rounded-2xl flex items-center justify-center shadow-xl border border-gray-100 hover:scale-110"><X size={24} /></button>
        </div>
        <div className="p-12 overflow-y-auto space-y-10">
          {step === 1 ? (
            <>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-6 opacity-60">Classification</label>
                <div className="grid grid-cols-2 gap-6">
                    {[ 
                        { id: ImpactType.PROBLEM, label: 'Report Issue', color: 'text-rose-600', active: 'bg-rose-50 border-rose-300 ring-4 ring-rose-50' }, 
                        { id: ImpactType.INITIATIVE, label: 'New Project', color: 'text-emerald-600', active: 'bg-emerald-50 border-emerald-300 ring-4 ring-emerald-50' } 
                    ].map(btn => ( 
                        <button key={btn.id} onClick={() => setType(btn.id as any)} className={`py-8 rounded-[2.5rem] text-sm font-black border-2 transition-all duration-500 ${type === btn.id ? btn.active + ' ' + btn.color : 'bg-white border-gray-100 text-gray-400 hover:border-gray-300 shadow-sm'}`}>{btn.label}</button> 
                    ))}
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-4 opacity-60">Action Subject</label>
