              </div>
            </>
          ) : (
            <div className="space-y-10 animate-fade-in">
              <div className="bg-gradient-to-br from-indigo-600 via-blue-700 to-purple-800 rounded-[3.5rem] p-12 text-white shadow-3xl relative overflow-hidden group">
