                            <span key={tag} className="text-[11px] font-black px-5 py-2.5 bg-white/10 rounded-2xl uppercase tracking-widest border border-white/10 shadow-lg backdrop-blur-md">#{tag}</span> 
                        ))}
                    </div>
                </div>
                <Sparkles className="absolute -right-20 -bottom-20 text-white/5 group-hover:scale-125 transition-transform duration-1000" size={400} />
              </div>
            </div>
          )}
        </div>
        <div className="p-10 border-t border-gray-50 bg-gray-50/50 flex justify-end gap-6">
            <button onClick={onClose} className="px-10 py-4 text-gray-400 font-black text-[12px] uppercase tracking-[0.2em] hover:text-gray-900 transition-colors">Terminate</button>
            <button 
                disabled={loading || !title || !description} 
                onClick={handleNext} 
                className="px-12 py-5 bg-gray-900 text-white font-black rounded-[1.5rem] hover:bg-black shadow-3xl shadow-gray-200 disabled:opacity-30 flex items-center gap-4 text-[12px] uppercase tracking-[0.2em] transition-all active:scale-95 group"
            >
                {loading ? (
                  <>
                    <Zap className="animate-spin text-emerald-400" size={18} />
                    Processing...
                  </>
                ) : (
                  <>
                    {step === 1 ? 'Start Engine' : 'Broadcast to City'}
                    <ChevronRight size={18} className="group-hover:translate-x-1 transition-transform" />
                  </>
                )}
            </button>
        </div>
      </div>
    </div>
  );
};

export default ImpactHack;

