const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: any) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    if (isOpen) { 
        setType(initialType || ImpactType.PROBLEM); 
        setTitle(prefilledTitle || ''); 
        setStep(1);
    }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try { 
          const result = await analyzeProblem(description); 
          setAiAnalysis(result); 
          setStep(2); 
      } catch (e) { 
          setStep(2); 
      } finally { 
          setLoading(false); 
      }
    } else {
      onSubmit({ title, description, type, tags: aiAnalysis?.tags || ['community'] });
      setTitle(''); setDescription(''); setAiAnalysis(null); 
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] border border-slate-200">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
            <h3 className="text-lg font-bold text-slate-900 tracking-tight">
                {step === 1 ? 'New Community Record' : 'System Synthesis'}
            </h3>
            <button onClick={onClose} className="text-slate-400 hover:text-slate-900 transition-colors"><X size={20} /></button>
        </div>
        <div className="p-8 overflow-y-auto space-y-6">
          {step === 1 ? (
            <>
              <div>
                <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Classification</label>
                <div className="grid grid-cols-2 gap-3">
                    {[ 
                        { id: ImpactType.PROBLEM, label: 'Report Gap', active: 'bg-rose-50 border-rose-200 text-rose-700' }, 
                        { id: ImpactType.INITIATIVE, label: 'New Action', active: 'bg-emerald-50 border-emerald-200 text-emerald-700' } 
                    ].map(btn => ( 
                        <button key={btn.id} onClick={() => setType(btn.id as any)} className={`py-3 rounded-lg text-xs font-bold border transition-colors ${type === btn.id ? btn.active : 'bg-white border-slate-100 text-slate-400 hover:border-slate-300'}`}>{btn.label}</button> 
                    ))}
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Subject</label>
                <input value={title} onChange={e => setTitle(e.target.value)} className="w-full px-4 py-3 rounded-lg bg-slate-50 border border-slate-200 focus:bg-white focus:border-slate-900 outline-none font-bold text-slate-900 transition-all" placeholder="Clear title..." />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2">Context</label>
                <textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full px-4 py-3 rounded-lg bg-slate-50 border border-slate-200 focus:bg-white focus:border-slate-900 outline-none h-32 resize-none font-medium text-slate-600 transition-all" placeholder="What needs to happen?" />
              </div>
            </>
          ) : (
            <div className="space-y-6">
              <div className="bg-slate-900 rounded-lg p-6 text-white shadow-lg">
                    <p className="text-slate-200 text-sm font-medium leading-relaxed mb-4">{aiAnalysis?.summary || "Analyzing node..."}</p>
                    <div className="flex gap-2 flex-wrap">
                        {aiAnalysis?.tags?.map((tag: string) => ( 
                            <span key={tag} className="text-[9px] font-bold px-3 py-1 bg-white/10 rounded uppercase tracking-wider border border-white/10">#{tag}</span> 
                        ))}
                    </div>
              </div>
            </div>
          )}
        </div>
        <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-end gap-3">
            <button onClick={onClose} className="px-5 py-2 text-slate-400 font-bold text-xs uppercase tracking-wider hover:text-slate-900 transition-colors">Discard</button>
            <button 
                disabled={loading || !title || !description} 
                onClick={handleNext} 
                className="px-6 py-2.5 bg-slate-900 text-white font-bold rounded-lg hover:bg-slate-800 disabled:opacity-30 flex items-center gap-2 text-xs uppercase tracking-wider transition-all"
            >
                {loading ? 'Synthesizing...' : (step === 1 ? 'Start Engine' : 'Publish to Feed')}
            </button>
        </div>
      </div>
    </div>
  );
};

