import React from 'react';
import { Milestone } from '../types.ts';
import { CheckCircle2, Circle, Clock, Zap, Target } from 'lucide-react';

interface Props {
  milestones: Milestone[];
  onToggle: (milestoneId: string) => void;
}

const MilestoneTracker: React.FC<Props> = ({ milestones, onToggle }) => {
  const completedCount = milestones.filter(m => m.isCompleted).length;
  const progress = milestones.length > 0 ? (completedCount / milestones.length) * 100 : 0;

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center mb-4">
        <div>
          <h4 className="font-bold text-slate-900 uppercase text-xs tracking-wider">Roadmap Progress</h4>
          <p className="text-[10px] text-slate-400 uppercase tracking-widest mt-0.5">
            {completedCount} of {milestones.length} Strategic Nodes Secured
          </p>
        </div>
        <div className="text-right">
          <span className="text-3xl font-bold text-slate-900 tabular-nums">{Math.round(progress)}%</span>
        </div>
      </div>

      <div className="w-full bg-slate-200 rounded-full h-2 overflow-hidden shadow-inner border border-slate-100">
        <div 
          className="bg-indigo-600 h-full transition-all duration-700 ease-in-out" 
          style={{ width: `${progress}%` }}
        />
      </div>

      <div className="space-y-4 mt-8">
        {milestones.map((m, idx) => (
          <div 
            key={m.id} 
            className={`flex items-start gap-5 p-5 rounded-lg border transition-colors ${
              m.isCompleted 
                ? 'bg-slate-50 border-emerald-100' 
                : 'bg-white border-slate-100'
            }`}
          >
            <button 
              onClick={() => onToggle(m.id)}
              className={`mt-0.5 transition-colors ${
                m.isCompleted ? 'text-emerald-500' : 'text-slate-300 hover:text-slate-900'
              }`}
            >
              {m.isCompleted ? <CheckCircle2 size={24} /> : <Circle size={24} strokeWidth={1.5} />}
            </button>
            <div className="flex-1">
              <p className={`font-bold text-sm tracking-tight ${m.isCompleted ? 'text-slate-400 line-through' : 'text-slate-900'}`}>
                {idx + 1}. {m.title}
              </p>
              <p className={`text-xs mt-1 leading-relaxed ${m.isCompleted ? 'text-slate-400 opacity-60' : 'text-slate-500'}`}>
                {m.description}
              </p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default MilestoneTracker;

