import React, { useState, useMemo } from 'react';
import { ImpactEntry, ImpactType, Milestone, UserStats } from './types.ts';
import { analyzeProblem, generateMilestones } from './services/geminiService.ts';
import ImpactCard from './components/ImpactCard.tsx';
import MilestoneTracker from './components/MilestoneTracker.tsx';
import { 
  Home, PlusCircle, Globe, 
  Map as MapIcon, ChevronRight, Send, AlertTriangle, Sparkles, X, Layout,
