    timestamp: "1 hour ago",
    votes: 56,
    followersCount: 34,
    tags: ["safety", "community-action"],
    comments: [],
    participantsCount: 8,
    status: 'active',
    linkedProblemId: '1',
    milestones: [
      { id: 'm1', title: 'Recruit 10 volunteers', description: 'Find locals to join evening patrols.', isCompleted: true },
      { id: 'm2', title: 'Solar light proposal', description: 'Present alternative lighting plan to council.', isCompleted: false },
    ]
  }
];

type ViewState = 'home' | 'initiatives' | 'impact' | 'feed' | 'milestones';

const ImpactHack = () => {
  const [entries, setEntries] = useState<ImpactEntry[]>(INITIAL_ENTRIES);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [joinedIds, setJoinedIds] = useState<Set<string>>(new Set(['2']));
  const [view, setView] = useState<ViewState>('home');
  const [createConfig, setCreateConfig] = useState<{type?: ImpactType, title?: string, problemId?: string}>({});
  const [userStats, setUserStats] = useState<UserStats>({
    problemsReported: 1, initiativesJoined: 1, milestonesReached: 1, totalKarma: 450
  });

  const handleVote = (id: string, delta: number) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, votes: e.votes + delta } : e));
  };

  const handleJoin = (id: string) => {
    setJoinedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
        setUserStats(s => ({ ...s, initiativesJoined: Math.max(0, s.initiativesJoined - 1) }));
      } else {
        next.add(id);
        setUserStats(s => ({ ...s, initiativesJoined: s.initiativesJoined + 1, totalKarma: s.totalKarma + 50 }));
      }
      return next;
    });
  };

  const handleToggleMilestone = (milestoneId: string) => {
    if (!selectedId) return;
    setEntries(prev => prev.map(entry => {
      if (entry.id !== selectedId || !entry.milestones) return entry;
      const milestone = entry.milestones.find(m => m.id === milestoneId);
      if (!milestone) return entry;
      const becomingCompleted = !milestone.isCompleted;
      if (becomingCompleted) {
        setUserStats(s => ({ ...s, milestonesReached: s.milestonesReached + 1, totalKarma: s.totalKarma + 25 }));
      } else {
        setUserStats(s => ({ ...s, milestonesReached: Math.max(0, s.milestonesReached - 1), totalKarma: s.totalKarma - 25 }));
      }
      return {
        ...entry,
        milestones: entry.milestones.map(m => m.id === milestoneId ? { ...m, isCompleted: !m.isCompleted } : m)
      };
    }));
  };

  const handlePost = async (partial: Partial<ImpactEntry>) => {
    const newId = Date.now().toString();
    let milestones: Milestone[] = [];
    if (partial.type === ImpactType.INITIATIVE) {
      milestones = await generateMilestones(partial.title!, partial.description!);
    }
    // Fix: removed duplicate followersCount property
    const newEntry: ImpactEntry = {
      id: newId, 
      type: partial.type!, 
      title: partial.title!, 
      description: partial.description!,
      author: 'you', 
      location: `Local Area`, 
      region: "Central", 
      timestamp: 'Just now',
      votes: 1, 
      followersCount: 1, 
      tags: partial.tags || ['community'], 
      comments: [],
      participantsCount: partial.type === ImpactType.INITIATIVE ? 1 : 0,
      milestones: partial.type === ImpactType.INITIATIVE ? milestones : undefined,
      status: 'active', 
      linkedProblemId: createConfig.problemId
    };

    setEntries(prev => {
      let updated = [newEntry, ...prev];
      if (createConfig.problemId) {
        updated = updated.map(e => (e.id === createConfig.problemId) ? { ...e, linkedInitiativeIds: [...(e.linkedInitiativeIds || []), newId] } : e);
      }
      return updated;
    });

    if (partial.type === ImpactType.PROBLEM) {
        setUserStats(s => ({ ...s, problemsReported: s.problemsReported + 1, totalKarma: s.totalKarma + 100 }));
    }

    setIsModalOpen(false); 
    setCreateConfig({}); 
    setSelectedId(newId);
    if (partial.type === ImpactType.INITIATIVE) handleJoin(newId);
  };

  const selectedEntry = entries.find(e => e.id === selectedId);

  const navItems = [
    { id: 'home', icon: <Home size={18} />, label: 'Home', color: 'text-blue-600' },
    { id: 'initiatives', icon: <Rocket size={18} />, label: 'Initiatives', color: 'text-emerald-600' },
    { id: 'impact', icon: <Award size={18} />, label: 'Your impact', color: 'text-amber-600' },
    { id: 'feed', icon: <Layout size={18} />, label: 'Action feed', color: 'text-rose-600' },
    { id: 'milestones', icon: <CheckCircle size={18} />, label: 'Milestones', color: 'text-cyan-600' },
  ];

  const filteredEntries = useMemo(() => {
    if (view === 'initiatives') return entries.filter(e => e.type === ImpactType.INITIATIVE);
    return entries;
  }, [entries, view]);

  return (
    <div className="min-h-screen flex text-slate-700">
      {/* Sidebar Navigation */}
      <aside className="w-72 standard-sidebar flex flex-col sticky top-0 h-screen shrink-0 z-20">
        <div className="p-8 pb-4">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => { setSelectedId(null); setView('home'); }}>
            <div className="w-9 h-9 bg-indigo-600 rounded-lg flex items-center justify-center shadow-md shadow-indigo-100 group-hover:rotate-3 transition-transform">
              <Zap className="text-white fill-current" size={18} />
            </div>
            <span className="text-lg font-bold text-slate-900 tracking-tight">ImpactHack</span>
          </div>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-1">
          {navItems.map(item => (
            <button 
              key={item.id} 
              onClick={() => { setView(item.id as any); setSelectedId(null); }} 
              className={`w-full flex items-center gap-3 px-4 py-2.5 font-bold text-[13px] rounded-xl transition-all ${
                view === item.id && !selectedId 
                  ? 'bg-slate-100 text-slate-900 shadow-sm' 
                  : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
              }`}
            >
              <span className={view === item.id && !selectedId ? item.color : 'text-slate-400 group-hover:text-slate-600 transition-colors'}>
                {item.icon}
              </span>
              {item.label}
            </button>
          ))}
        </nav>

        {/* Sidebar Actions */}
        <div className="p-6 border-t border-slate-100 space-y-3">
          <button 
            onClick={() => { setCreateConfig({ type: ImpactType.INITIATIVE }); setIsModalOpen(true); }}
            className="w-full bg-emerald-600 text-white p-3 rounded-xl font-bold text-[11px] uppercase tracking-wider hover:bg-emerald-700 transition-colors flex items-center justify-center gap-2 shadow-lg shadow-emerald-50"
          >
            <Rocket size={14} /> Make Initiative
          </button>
          <button 
            onClick={() => { setCreateConfig({ type: ImpactType.PROBLEM }); setIsModalOpen(true); }}
            className="w-full bg-rose-600 text-white p-3 rounded-xl font-bold text-[11px] uppercase tracking-wider hover:bg-rose-700 transition-colors flex items-center justify-center gap-2 shadow-lg shadow-rose-50"
          >
            <AlertTriangle size={14} /> File Report
          </button>
          <button 
            onClick={() => { setView('initiatives'); setSelectedId(null); }}
            className="w-full bg-white border border-slate-200 text-slate-700 p-3 rounded-xl font-bold text-[11px] uppercase tracking-wider hover:border-slate-400 transition-colors flex items-center justify-center gap-2"
          >
            <UserPlus size={14} /> Join Initiative
          </button>
        </div>
      </aside>

      <main className="flex-1 min-w-0 p-8 lg:p-12 z-10">
        <div className="max-w-4xl mx-auto">
          {selectedId && selectedEntry ? (
            <DetailView 
              entry={selectedEntry} 
              isJoined={joinedIds.has(selectedEntry.id)} 
              onVote={handleVote} 
              onToggleMilestone={handleToggleMilestone}
              onJoin={handleJoin}
              onBack={() => setSelectedId(null)}
              onPropose={() => { 
                setCreateConfig({ type: ImpactType.INITIATIVE, title: `Fix: ${selectedEntry.title}`, problemId: selectedEntry.id }); 
                setIsModalOpen(true); 
              }}
            />
          ) : (
            <div className="animate-view-entry space-y-12">
              {view === 'home' && (
                <HomeView stats={userStats} entries={entries} onNavigate={setView} setDetail={setSelectedId} />
              )}

              {view === 'impact' && (
                <ImpactDashboard stats={userStats} entries={entries} joinedIds={joinedIds} />
              )}

              {view === 'milestones' && (
                <MilestonesHall entries={entries} joinedIds={joinedIds} />
              )}

              {(view === 'initiatives' || view === 'feed') && (
                <div className="space-y-6">
                  <header className="flex flex-col gap-2 mb-8">
                    <h2 className="text-3xl font-bold text-slate-900 tracking-tight">
                      {view === 'initiatives' ? 'Open Initiatives' : 'Community Activity'}
                    </h2>
                    <p className="text-slate-500 font-medium">
                      {view === 'initiatives' ? 'Collaborate on projects to solve shared community problems.' : 'A live feed of reported issues and collaborative solutions.'}
                    </p>
                  </header>
                  <div className="grid gap-4">
                    {filteredEntries.map(entry => (
                      <ImpactCard 
                        key={entry.id} 
                        entry={entry} 
                        onVote={handleVote} 
                        onClick={setSelectedId} 
                        onJoin={handleJoin} 
                        isJoined={joinedIds.has(entry.id)} 
                      />
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </main>

      <CreateModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSubmit={handlePost} 
        initialType={createConfig.type} 
        prefilledTitle={createConfig.title} 
      />
    </div>
  );
};

