const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: any) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    if (isOpen) { 
        setType(initialType || ImpactType.PROBLEM); 
        setTitle(prefilledTitle || ''); 
        setStep(1);
    }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try { 
          const result = await analyzeProblem(description); 
          setAiAnalysis(result); 
          setStep(2); 
      } catch (e) { 
          setStep(2); 
      } finally { 
          setLoading(false); 
      }
    } else {
      onSubmit({ title, description, type, tags: aiAnalysis?.tags || ['community'] });
      setTitle(''); setDescription(''); setAiAnalysis(null); 
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-md p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-xl overflow-hidden flex flex-col max-h-[90vh] border border-slate-200">
        <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50">
            <h3 className="text-xl font-bold text-slate-900 tracking-tight flex items-center gap-3">
                {step === 1 ? (
                  type === ImpactType.PROBLEM ? <AlertTriangle size={24} className="text-rose-500" /> : 
                  type === ImpactType.FORUM ? <HelpCircle size={24} className="text-violet-500" /> :
                  <Rocket size={24} className="text-emerald-500" />
                ) : <Sparkles size={24} className="text-indigo-500" />}
                {step === 1 ? 'New Community Node' : 'Intelligence Summary'}
            </h3>
            <button onClick={onClose} className="text-slate-400 hover:text-slate-900 transition-colors p-2 hover:bg-slate-100 rounded-lg"><X size={20} /></button>
        </div>
        <div className="p-10 overflow-y-auto space-y-8">
          {step === 1 ? (
            <>
              <div>
                <label className="block text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-4">Node Classification</label>
                <div className="grid grid-cols-3 gap-3">
                    {[ 
                        { id: ImpactType.PROBLEM, label: 'Report Issue', color: 'text-rose-700', active: 'bg-rose-50 border-rose-200' }, 
                        { id: ImpactType.FORUM, label: 'Seek Advice', color: 'text-violet-700', active: 'bg-violet-50 border-violet-200' },
                        { id: ImpactType.INITIATIVE, label: 'New Project', color: 'text-emerald-700', active: 'bg-emerald-50 border-emerald-200' } 
                    ].map(btn => ( 
                        <button key={btn.id} onClick={() => setType(btn.id as any)} className={`py-4 rounded-xl text-[11px] font-bold border-2 transition-all ${type === btn.id ? btn.active + ' ' + btn.color : 'bg-white border-slate-100 text-slate-400 hover:border-slate-300'}`}>{btn.label}</button> 
                    ))}
                </div>
              </div>
              <div>
                <label className="block text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Primary Subject</label>
                <input value={title} onChange={e => setTitle(e.target.value)} className="w-full px-5 py-4 rounded-xl bg-slate-50 border-2 border-slate-50 focus:bg-white focus:border-slate-900 outline-none font-bold text-slate-900 text-lg transition-all" placeholder="Clear title..." />
              </div>
              <div>
                <label className="block text-[11px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Contextual Details</label>
                <textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full px-5 py-4 rounded-xl bg-slate-50 border-2 border-slate-50 focus:bg-white focus:border-slate-900 outline-none h-40 resize-none font-medium text-slate-600 text-lg transition-all" placeholder="What is the local impact or your specific question?" />
              </div>
            </>
          ) : (
            <div className="space-y-6">
              <div className="bg-slate-900 rounded-2xl p-8 text-white shadow-xl relative overflow-hidden group">
                    <div className="relative z-10">
                        <div className="flex items-center gap-3 mb-4">
                           <Shield className="text-emerald-400" size={20} />
                           <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Analysis Summary</span>
                        </div>
                        <p className="text-slate-100 text-lg font-medium leading-relaxed mb-8">{aiAnalysis?.summary || "Processing..."}</p>
                        <div className="flex gap-3 flex-wrap">
                            {aiAnalysis?.tags?.map((tag: string) => ( 
                                <span key={tag} className="text-[10px] font-bold px-4 py-1.5 bg-white/10 rounded-lg uppercase tracking-wider border border-white/10 backdrop-blur-sm">#{tag}</span> 
                            ))}
                        </div>
                    </div>
              </div>
            </div>
          )}
        </div>
        <div className="p-8 border-t border-slate-100 bg-slate-50 flex justify-end gap-4">
            <button onClick={onClose} className="px-6 py-2.5 text-slate-400 font-bold text-xs uppercase tracking-widest hover:text-slate-900 transition-colors">Discard</button>
            <button 
                disabled={loading || !title || !description} 
                onClick={handleNext} 
                className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 disabled:opacity-30 flex items-center gap-3 text-xs uppercase tracking-widest transition-all shadow-lg shadow-indigo-100"
            >
                {loading ? (
                    <>
                       <Zap className="animate-spin text-indigo-200" size={16} /> 
                       Synthesizing...
                    </>
                ) : (step === 1 ? 'Analyze & Prep' : 'Broadcast Board')}
            </button>
        </div>
      </div>
    </div>
  );
};

export default ImpactHack;

import React from 'react';
import { ImpactEntry, ImpactType } from '../types.ts';
import { MessageSquare, ArrowBigUp, ArrowBigDown, MapPin, Users, CheckCircle, Lightbulb, UserPlus, Zap, HelpCircle } from 'lucide-react';

interface Props {
