  onVote: (id: string, delta: number) => void;
  onClick: (id: string) => void;
  onJoin?: (id: string) => void;
  isJoined?: boolean;
}

const ImpactCard: React.FC<Props> = ({ entry, onVote, onClick, onJoin, isJoined }) => {
  const isProblem = entry.type === ImpactType.PROBLEM;
  const isForum = entry.type === ImpactType.FORUM;

  return (
    <div 
      className={`bg-white rounded-2xl border border-slate-200 overflow-hidden hover:border-slate-300 transition-all cursor-pointer group flex shadow-sm hover:shadow-md border-l-4 ${
        isProblem ? 'border-l-rose-500' : 
        isForum ? 'border-l-violet-500' : 
        'border-l-emerald-500'
      }`}
      onClick={() => onClick(entry.id)}
    >
      {/* Vote Area */}
      <div className={`w-16 shrink-0 flex flex-col items-center py-8 space-y-2 bg-slate-50/50 border-r border-slate-100 transition-colors group-hover:bg-slate-50`}>
        <button 
          onClick={(e) => { e.stopPropagation(); onVote(entry.id, 1); }}
          className="text-slate-300 hover:text-indigo-600 transition-colors p-1"
        >
          <ArrowBigUp size={26} />
        </button>
        <span className={`font-bold text-lg tracking-tight text-slate-900 tabular-nums`}>
          {entry.votes}
        </span>
        <button 
          onClick={(e) => { e.stopPropagation(); onVote(entry.id, -1); }}
          className="text-slate-300 hover:text-rose-600 transition-colors p-1"
        >
          <ArrowBigDown size={26} />
        </button>
      </div>

      <div className="p-7 flex-1 flex flex-col">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-4">
            <span className={`px-2.5 py-1 rounded-md text-[9px] font-bold uppercase tracking-wider border shadow-sm ${
              isProblem ? 'bg-rose-50 text-rose-700 border-rose-100' : 
              isForum ? 'bg-violet-50 text-violet-700 border-violet-100' :
              'bg-emerald-50 text-emerald-700 border-emerald-100'
            }`}>
              {entry.type === ImpactType.FORUM ? 'ADVICE' : entry.type}
            </span>
            <div className="flex items-center gap-2">
               <div className="w-6 h-6 rounded bg-slate-100 border border-slate-200 flex items-center justify-center font-bold text-[8px] text-slate-500 uppercase">{entry.author[0]}</div>
               <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">u/{entry.author}</span>
            </div>
          </div>
          {isJoined && (
            <span className="text-[9px] font-bold text-emerald-600 bg-emerald-50 px-2.5 py-1 rounded-lg border border-emerald-100 flex items-center gap-1.5 shadow-sm">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
              ENGAGED
            </span>
          )}
        </div>

        <h3 className={`text-2xl font-bold text-slate-900 transition-colors mb-3 leading-tight tracking-tight ${
          isForum ? 'group-hover:text-violet-600' : 'group-hover:text-indigo-600'
        }`}>
          {entry.title}
        </h3>

        <p className="text-slate-500 text-base line-clamp-2 mb-6 font-medium leading-relaxed">
          {entry.description}
        </p>

        <div className="mt-auto flex items-center justify-between text-slate-400 text-[10px] font-bold uppercase tracking-[0.2em] border-t border-slate-50 pt-5">
          <div className="flex items-center gap-8">
            <div className={`flex items-center gap-2 transition-colors ${isForum ? 'group-hover:text-violet-600' : 'group-hover:text-slate-800'}`}>
               {isForum ? <HelpCircle size={16} /> : <MessageSquare size={16} />}
               <span>{entry.comments.length} {isForum ? 'Advice Logs' : 'Logged'}</span>
            </div>
            <div className="flex items-center gap-2">
               <MapPin size={16} className="text-rose-400" /> 
               <span>{entry.location}</span>
            </div>
          </div>
          {!isProblem && !isForum && !isJoined && (
            <button 
              onClick={(e) => { e.stopPropagation(); onJoin?.(entry.id); }}
              className="text-emerald-600 hover:text-emerald-700 font-bold flex items-center gap-2 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100 transition-all hover:shadow-md"
            >
              <UserPlus size={14} /> Join Unit
            </button>
          )}
          {isForum && (
            <div className="text-violet-600 font-bold flex items-center gap-2">
               Ask Harbor <ChevronRight size={14} />
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ImpactCard;

